#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205,M=6005;
int n,w,f[N];
ll ans[N];
struct node
{
	int u,v,w,id;
	bool operator<(const node other) const
	{
		return w<other.w;
	}
} a[1000005];
int find(int x)
{
	if(f[x]==x) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>w;
	for(int i=1;i<=w;i++)
	{
		int aa,b,c;
		cin>>aa>>b>>c;
		a[i]=node{aa,b,c,i};
	}
	sort(a+1,a+1+w);
	for(int i=1;i<=w;i++)
	{
		int ans=0,cnt=0;
		for(int j=1;j<=n;j++)
		{
			f[j]=j;
		}
		for(int j=1;j<=w;j++)
		{
			int fu=find(a[j].u),fv=find(a[j].v);
//			cout<<fu<<" "<<fv<<"  ??? ";
			if((a[j].id<=i)&&(fu!=fv))
			{
				f[fu]=fv;
//				cout<<"yes";
				ans+=a[j].w;
				cnt++;
			}
//			cout<<"\n";
			if(cnt==n-1)
			{
				cout<<ans<<"\n";
				goto end;
			}
		}
		cout<<"-1\n";
		end: ;
	}
	return 0;
}
